sql_answer:
SELECT location FROM bridge
INTERSECT
SELECT location FROM mill;

SELECT COUNT(*) AS so_luong
FROM architect
WHERE nationality IN ('American', 'German');

SELECT architect_id FROM bridge
EXCEPT
SELECT architect_id FROM mill;

SELECT name
FROM (
    SELECT name, built_year, MAX(built_year) OVER (PARTITION BY architect_id) AS max_built_year
    FROM mill
) AS sub
WHERE built_year < max_built_year;

SELECT a.id, a.name
FROM architect a
WHERE EXISTS (
    SELECT 1 FROM bridge b WHERE b.architect_id = a.id
) AND NOT EXISTS (
    SELECT 1 FROM bridge b WHERE b.architect_id = a.id AND b.location NOT LIKE '%China%'
);

SELECT a.id, a.name, a.nationality, a.gender
FROM architect a
WHERE a.nationality LIKE '%,%';

SELECT *
FROM Engineer_Visits
WHERE contact_staff_id IS NULL;

SELECT S.Sex, COUNT(*) AS student_count
FROM Student S
GROUP BY S.Sex;

SELECT *
FROM Apartment_Buildings
WHERE building_address LIKE '%, AL%' OR building_address LIKE '%, CA%';

SELECT a.apt_id
FROM Apartments a
WHERE a.bathroom_count = (SELECT bathroom_count FROM Apartments WHERE apt_id = 1);

SELECT guest_id, gender_code, guest_first_name, guest_last_name, date_of_birth
FROM Guests
WHERE date_of_birth >= '1974-01-01' AND date_of_birth < '1979-01-01';

SELECT booking_status_code AS "Trạng thái đặt chỗ", COUNT(*) AS "Số lượt đặt"
FROM Apartment_Bookings
GROUP BY booking_status_code;

SELECT *
FROM Apartment_Bookings
WHERE CAST(strftime('%m', booking_start_date) AS INTEGER) BETWEEN 6 AND 8;

SELECT s.StuID, s.LName, s.Fname, s.Age
FROM Student s
WHERE s.Age BETWEEN 18 AND 20;

SELECT Major, COUNT(StuID) AS so_sinh_vien
FROM Student
GROUP BY Major;
